import { useEffect, useState } from "react";

const SIZE = 10;

function point(x, y) {
  return { x, y };
}

function add(a, b) {
  return point(a.x + b.x, a.y + b.y);
}

function equal(a, b) {
  return a.x === b.x && a.y === b.y;
}

function randomFood() {
  return point(
    Math.floor(Math.random() * SIZE),
    Math.floor(Math.random() * SIZE)
  );
}

export default function Snake() {
  const [snake, setSnake] = useState([point(5, 5)]);
  const [food, setFood] = useState(point(2, 2));
  const [direction, setDirection] = useState(point(0, 0));
  const [score, setScore] = useState(0);
  const [gameOver, setGameOver] = useState(false);

  function reset() {
    setSnake([point(5, 5)]);
    setFood(point(2, 2));
    setDirection(point(0, 0));
    setScore(0);
    setGameOver(false);
  }

  useEffect(() => {
    if (gameOver) return;

    const timer = setInterval(() => {
      const head = add(
        snake[0],
        direction
      );

      const outside =
        head.x < 0 ||
        head.x >= SIZE ||
        head.y < 0 ||
        head.y >= SIZE;

      if (outside) {
        setGameOver(true);
        return;
      }

      if (equal(head, food)) {
        setSnake([
          head,
          ...snake,
        ]);

        setFood(randomFood());
        setScore(score => score + 1);
      } else {
        setSnake([
          head,
          ...snake.slice(0, -1),
        ]);
      }

    }, 300);

    return () => clearInterval(timer);
  }, [snake, food, direction, gameOver]);

  function keyDown(e) {
    if (e.key === "ArrowUp") setDirection(point(0, -1));
    if (e.key === "ArrowDown") setDirection(point(0, 1));
    if (e.key === "ArrowLeft") setDirection(point(-1, 0));
    if (e.key === "ArrowRight") setDirection(point(1, 0));
  }

  function color(cell) {
    if (snake.some(part => equal(part, cell))) {
      return "green";
    }

    if (equal(food, cell)) {
      return "red";
    }

    return "white";
  }

  return (
    <main onKeyDown={keyDown} tabIndex={0} autoFocus>
      <h1>🐍 Snake</h1>

      <p>Score: {score}</p>

      {gameOver && (
        <p>
          Game Over!
          <button onClick={reset}>
            Restart
          </button>
        </p>
      )}

      <table>
        <tbody>
          {Array.from({ length: SIZE }, (_, y) => (
            <tr key={y}>
              {Array.from({ length: SIZE }, (_, x) => (
                <td
                  key={x}
                  style={{
                    width: 25,
                    height: 25,
                    border: "1px solid",
                    background: color(point(x, y)),
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
